@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p class="drop-zone-prompt">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
                @if (entry.IsOversize)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> — @FormatSize(entry.Info.Size) (@entry.Info.Type)
                        <span class="error-message">File exceeds 10 MB limit</span>
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> — @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10 * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isOver)
    {
        _isDragOver = isOver;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            _files.Add(new FileEntry(file, file.Size > MaxSizeBytes));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("disposeDropZone", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record FileEntry(FileInfo Info, bool IsOversize);
}

const registrations = new WeakMap();

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    function onDragEnter(e) {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
        }
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        e.preventDefault();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        dragCounter = 0;

        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'unknown' });
        }

        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    registrations.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function disposeDropZone(element) {
    const handlers = registrations.get(element);
    if (!handlers) return;

    element.removeEventListener('dragenter', handlers.onDragEnter);
    element.removeEventListener('dragover', handlers.onDragOver);
    element.removeEventListener('dragleave', handlers.onDragLeave);
    element.removeEventListener('drop', handlers.onDrop);

    registrations.delete(element);
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.drop-zone-prompt {
    margin: 0;
    color: #6c757d;
    font-size: 1.1rem;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 12px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 6px;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.error-message {
    color: #dc3545;
    font-size: 0.85rem;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
    flex-shrink: 0;
}

.btn-remove:hover {
    background: #dc3545;
    color: #fff;
}

