@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p class="drop-zone-prompt">Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _files)
        {
            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
                @if (entry.IsOversize)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> — @FormatSize(entry.Info.Size) (@entry.Info.Type)
                        <span class="error-message">File exceeds 10 MB limit</span>
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> — @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10 * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isOver)
    {
        _isDragOver = isOver;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            _files.Add(new FileEntry(file, file.Size > MaxSizeBytes));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _files
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("disposeDropZone", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record FileEntry(FileInfo Info, bool IsOversize);
}

