const registrations = new WeakMap();

export function initDropZone(element, dotNetRef) {
    let dragCounter = 0;

    function onDragEnter(e) {
        e.preventDefault();
        dragCounter++;
        if (dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
        }
    }

    function onDragOver(e) {
        e.preventDefault();
    }

    function onDragLeave(e) {
        e.preventDefault();
        dragCounter--;
        if (dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    }

    function onDrop(e) {
        e.preventDefault();
        dragCounter = 0;

        const files = [];
        for (const file of e.dataTransfer.files) {
            files.push({ name: file.name, size: file.size, type: file.type || 'unknown' });
        }

        dotNetRef.invokeMethodAsync('OnFilesDropped', files);
    }

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    registrations.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function disposeDropZone(element) {
    const handlers = registrations.get(element);
    if (!handlers) return;

    element.removeEventListener('dragenter', handlers.onDragEnter);
    element.removeEventListener('dragover', handlers.onDragOver);
    element.removeEventListener('dragleave', handlers.onDragLeave);
    element.removeEventListener('drop', handlers.onDrop);

    registrations.delete(element);
}

